The JACS codebase uses a TrustTestGuard pattern for tests that modify the HOME environment variable: use std::env;
use tempfile::TempDir; /// RAII guard for test isolation that ensures HOME is restored even on panic.
struct TrustTestGuard { _temp_dir: TempDir, original_home: Option<String>,
} impl TrustTestGuard { fn new() -> Self { // Save original HOME before modifying let original_home = env::var("HOME").ok(); let temp_dir = TempDir::new().expect("Failed to create temp directory"); // SAFETY: Only used in #[serial] tests - no concurrent access unsafe { env::set_var("HOME", temp_dir.path().to_str().unwrap()); } Self { _temp_dir: temp_dir, original_home, } }
} impl Drop for TrustTestGuard { fn drop(&mut self) { // Restore original HOME even during panic unwinding unsafe { match &self.original_home { Some(home) => env::set_var("HOME", home), None => env::remove_var("HOME"), } } }
} // Usage in tests:
#[test]
#[serial] // Use serial_test crate to prevent parallel execution
fn test_with_isolated_home() { let _guard = TrustTestGuard::new(); // Setup // Test code here - HOME points to temp directory // Guard automatically restores HOME on drop, even if test panics
} Key benefits: Panic safety : Cleanup runs even if the test panics No manual cleanup : Drop trait handles restoration automatically Environment isolation : Each test gets a fresh temporary directory Composable : Multiple guards can be combined for complex setups

