Here is a complete example of a JWT evidence adapter: use crate::attestation::adapters::EvidenceAdapter;
use crate::attestation::digest::compute_digest_set_bytes;
use crate::attestation::types::*;
use serde_json::Value;
use std::error::Error; #[derive(Debug)]
pub struct JwtAdapter; impl EvidenceAdapter for JwtAdapter { fn kind(&self) -> &str { "jwt" } fn normalize( &self, raw: &[u8], metadata: &Value, ) -> Result<(Vec<Claim>, EvidenceRef), Box<dyn Error>> { // 1. Parse the JWT (header.payload.signature) let jwt_str = std::str::from_utf8(raw)?; let parts: Vec<&str> = jwt_str.split('.').collect(); if parts.len() != 3 { return Err("Invalid JWT: expected 3 dot-separated parts".into()); } // 2. Decode the payload (base64url) let payload_bytes = base64::Engine::decode( &base64::engine::general_purpose::URL_SAFE_NO_PAD, parts[1], )?; let payload: Value = serde_json::from_slice(&payload_bytes)?; // 3. Compute content-addressable digests let digests = compute_digest_set_bytes(raw); // 4. Extract claims (only non-PII fields per TRD Decision 14) let mut claims = vec![]; if let Some(iss) = payload.get("iss") { claims.push(Claim { name: "jwt-issuer".into(), value: iss.clone(), confidence: Some(0.8), assurance_level: Some(AssuranceLevel::Verified), issuer: iss.as_str().map(String::from), issued_at: Some(crate::time_utils::now_rfc3339()), }); } if let Some(sub) = payload.get("sub") { claims.push(Claim { name: "jwt-subject".into(), value: sub.clone(), confidence: Some(0.8), assurance_level: Some(AssuranceLevel::Verified), issuer: None, issued_at: None, }); } // 5. Build the evidence reference let evidence = EvidenceRef { kind: EvidenceKind::Jwt, digests, uri: metadata.get("uri").and_then(|v| v.as_str()).map(String::from), embedded: raw.len() < 65536, embedded_data: if raw.len() < 65536 { Some(Value::String(jwt_str.to_string())) } else { None }, collected_at: crate::time_utils::now_rfc3339(), resolved_at: None, sensitivity: EvidenceSensitivity::Restricted, // JWTs may contain PII verifier: VerifierInfo { name: "jacs-jwt-adapter".into(), version: env!("CARGO_PKG_VERSION").into(), }, }; Ok((claims, evidence)) } fn verify_evidence( &self, evidence: &EvidenceRef, ) -> Result<EvidenceVerificationResult, Box<dyn Error>> { // Re-verify the digest let digest_valid = if let Some(ref data) = evidence.embedded_data { let raw = data.as_str().unwrap_or("").as_bytes(); let recomputed = compute_digest_set_bytes(raw); recomputed.sha256 == evidence.digests.sha256 } else { // Cannot verify without embedded data or fetchable URI false }; // Check freshness (example: 5 minute max age) let freshness_valid = true; // Implement actual time check Ok(EvidenceVerificationResult { kind: "jwt".into(), digest_valid, freshness_valid, detail: if digest_valid { "JWT digest verified".into() } else { "JWT digest mismatch or data unavailable".into() }, }) }
}

