import { JacsAgent } from '@hai.ai/jacs';
import fs from 'fs';
import path from 'path'; class JacsDocumentStore { constructor(configPath, dataDir = './documents') { this.configPath = configPath; this.dataDir = dataDir; this.agent = null; } async initialize() { this.agent = new JacsAgent(); await this.agent.load(this.configPath); if (!fs.existsSync(this.dataDir)) { fs.mkdirSync(this.dataDir, { recursive: true }); } } async create(content) { const signedDoc = await this.agent.createDocument(JSON.stringify(content)); const doc = JSON.parse(signedDoc); const filename = `${doc.jacsId}.json`; const filepath = path.join(this.dataDir, filename); fs.writeFileSync(filepath, signedDoc); return { id: doc.jacsId, version: doc.jacsVersion, path: filepath }; } async get(documentId) { const filepath = path.join(this.dataDir, `${documentId}.json`); if (!fs.existsSync(filepath)) { return null; } const docString = fs.readFileSync(filepath, 'utf-8'); return JSON.parse(docString); } async verify(documentId) { const filepath = path.join(this.dataDir, `${documentId}.json`); if (!fs.existsSync(filepath)) { return { valid: false, error: 'Document not found' }; } const docString = fs.readFileSync(filepath, 'utf-8'); const isValid = await this.agent.verifyDocument(docString); return { valid: isValid, document: JSON.parse(docString) }; } list() { const files = fs.readdirSync(this.dataDir); return files .filter(f => f.endsWith('.json')) .map(f => f.replace('.json', '')); }
} // Usage
