import jacs from '@hai.ai/jacs';
import http from 'http'; async function main() { // Load JACS agent await jacs.load('./jacs.config.json'); // Prepare payload const payload = { message: "Hello, secure server!", data: { id: 123, value: "some data" }, timestamp: new Date().toISOString() }; // Sign the request const signedRequest = await jacs.signRequest(payload); // Send HTTP request const response = await sendRequest(signedRequest, 'localhost', 3000, '/api/echo'); // Verify the response const verifiedResponse = await jacs.verifyResponse(response); console.log('Verified payload:', verifiedResponse.payload);
} function sendRequest(body, host, port, path) { return new Promise((resolve, reject) => { const options = { hostname: host, port: port, path: path, method: 'POST', headers: { 'Content-Type': 'text/plain', 'Content-Length': Buffer.byteLength(body), }, }; const req = http.request(options, (res) => { let data = ''; res.on('data', chunk => data += chunk); res.on('end', () => { if (res.statusCode >= 200 && res.statusCode < 300) { resolve(data); } else { reject(new Error(`HTTP ${res.statusCode}: ${data}`)); } }); }); req.on('error', reject); req.write(body); req.end(); });
} main();

