app.use('/api', JACSExpressMiddleware({ configPath: './jacs.server.config.json'
})); // Route handler
app.post('/api/echo', (req, res) => { // Access verified payload from req.jacsPayload const payload = req.jacsPayload; if (!payload) { return res.status(400).send('JACS payload missing'); } console.log('Received verified payload:', payload); // Send response object - middleware will sign it automatically res.send({ echo: "Server says hello!", received: payload, timestamp: new Date().toISOString() });
}); app.listen(PORT, () => { console.log(`JACS Express server listening on port ${PORT}`);
});

